import json
import re
from collections import Counter

# Load metadata from file
metadata_path = locals()['var_functions.query_db:5']
with open(metadata_path, 'r') as f:
    metadata = json.load(f)

# Filter for Europe 2010-2020 and create year map
europe_article_years = {}
for record in metadata:
    year = int(record['publication_date'][:4])
    if 2010 <= year <= 2020 and record['region'] == 'Europe':
        europe_article_years[record['article_id']] = year

print('__RESULT__:')
print(json.dumps({
    'europe_articles': len(europe_article_years),
    'sample_ids': list(europe_article_years.keys())[:5]
}))
